def is_valid_number(value):
    """Check if a value is a valid number (not NaN, not inf)"""
    if value is None:
        return False
    if isinstance(value, (int, float)):
        return not (np.isnan(value) or np.isinf(value))
    return False


def get_robust_current_price(stock, hist):
    """Get current price with multiple fallback methods"""
    current_price = None
    
    try:
        if not hist.empty and len(hist) > 0:
            last_close = hist['Close'].iloc[-1]
            if is_valid_number(last_close) and last_close > 0:
                return float(last_close)
    except:
        pass
    
    try:
        info = stock.info
        if 'currentPrice' in info and info['currentPrice'] is not None:
            price = info['currentPrice']
            if is_valid_number(price) and price > 0:
                return float(price)
    except:
        pass
    
    try:
        info = stock.info
        if 'regularMarketPrice' in info and info['regularMarketPrice'] is not None:
            price = info['regularMarketPrice']
            if is_valid_number(price) and price > 0:
                return float(price)
    except:
        pass
    
    try:
        if hasattr(stock, 'fast_info') and hasattr(stock.fast_info, 'last_price'):
            price = stock.fast_info.last_price
            if is_valid_number(price) and price > 0:
                return float(price)
    except:
        pass
    
    try:
        today_data = stock.history(period='1d')
        if not today_data.empty and len(today_data) > 0:
            price = today_data['Close'].iloc[-1]
            if is_valid_number(price) and price > 0:
                return float(price)
    except:
        pass
    
    try:
        recent_data = stock.history(period='5d')
        if not recent_data.empty and len(recent_data) > 0:
            close_prices = recent_data['Close'].dropna()
            if len(close_prices) > 0:
                price = close_prices.iloc[-1]
                if is_valid_number(price) and price > 0:
                    return float(price)
    except:
        pass
    
    return None


def fetch_stock_data(ticker, start_date, end_date, max_retries=3):
    """Fetch historical stock data with retry mechanism and robust validation"""
    for attempt in range(max_retries):
        try:
            stock = yf.Ticker(ticker)
            hist = stock.history(start=start_date, end=end_date)
            
            if hist.empty or len(hist) < 252:
                return None
            
            current_price = get_robust_current_price(stock, hist)
            
            if current_price is None or current_price <= 0:
                return None
            
            try:
                info = stock.info
                company_name = info.get('longName', info.get('shortName', ticker.replace('.NS', '')))
            except:
                company_name = ticker.replace('.NS', '')
            
            return {
                'ticker': ticker,
                'name': company_name,
                'history': hist,
                'current_price': float(current_price)
            }
            
        except Exception as e:
            if attempt < max_retries - 1:
                time.sleep(1)
                continue
            else:
                return None
    
    return None


def calculate_cagr(start_price, end_price, years):
    """Calculate Compound Annual Growth Rate with validation"""
    try:
        if not is_valid_number(start_price) or not is_valid_number(end_price) or not is_valid_number(years):
            return 0
        if start_price <= 0 or end_price <= 0 or years <= 0:
            return 0
        cagr = (((end_price / start_price) ** (1 / years)) - 1) * 100
        return cagr if is_valid_number(cagr) else 0
    except:
        return 0


def calculate_sharpe_ratio(returns, risk_free_rate):
    """Calculate Sharpe Ratio with validation"""
    try:
        if len(returns) == 0:
            return 0
        
        returns_clean = returns.dropna()
        if len(returns_clean) == 0:
            return 0
        
        std_dev = returns_clean.std()
        if not is_valid_number(std_dev) or std_dev == 0:
            return 0
        
        excess_returns = returns_clean.mean() * 252 - (risk_free_rate / 100)
        volatility = std_dev * np.sqrt(252)
        
        if not is_valid_number(volatility) or volatility == 0:
            return 0
        
        sharpe = excess_returns / volatility
        return sharpe if is_valid_number(sharpe) else 0
    except:
        return 0


def calculate_max_drawdown(price_series):
    """Calculate Maximum Drawdown with validation"""
    try:
        if len(price_series) == 0:
            return -10
        
        price_clean = price_series.dropna()
        if len(price_clean) == 0 or price_clean.iloc[0] <= 0:
            return -10
        
        cumulative = price_clean / price_clean.iloc[0]
        running_max = cumulative.expanding().max()
        drawdown = (cumulative - running_max) / running_max
        max_dd = drawdown.min() * 100
        
        return max_dd if is_valid_number(max_dd) else -10
    except:
        return -10


def calculate_volatility(returns):
    """Calculate annualized volatility with validation"""
    try:
        if len(returns) == 0:
            return 20
        
        returns_clean = returns.dropna()
        if len(returns_clean) == 0:
            return 20
        
        std_dev = returns_clean.std()
        if not is_valid_number(std_dev):
            return 20
        
        vol = std_dev * np.sqrt(252) * 100
        return vol if is_valid_number(vol) else 20
    except:
        return 20


def analyze_stock(stock_data):
    """Perform comprehensive analysis on stock data with robust error handling"""
    try:
        hist = stock_data['history']
        close_prices = hist['Close'].dropna()
        
        if len(close_prices) < 100:
            return None
        
        daily_returns = close_prices.pct_change().dropna()
        years = len(close_prices) / 252
        
        start_price = close_prices.iloc[0]
        end_price = close_prices.iloc[-1]
        
        if not is_valid_number(start_price) or not is_valid_number(end_price):
            return None
        
        if start_price <= 0 or end_price <= 0:
            return None
        
        cagr = calculate_cagr(start_price, end_price, years)
        sharpe = calculate_sharpe_ratio(daily_returns, RISK_FREE_RATE)
        max_dd = calculate_max_drawdown(close_prices)
        volatility = calculate_volatility(daily_returns)
        
        cumulative_return = ((end_price - start_price) / start_price) * 100
        
        ema_200_series = close_prices.ewm(span=200, adjust=False).mean()
        ema_200 = ema_200_series.iloc[-1] if len(ema_200_series) > 0 else close_prices.iloc[-1]
        
        if not is_valid_number(stock_data['current_price']):
            return None
        
        result = {
            'ticker': stock_data['ticker'],
            'name': stock_data['name'],
            'current_price': float(stock_data['current_price']),
            'cagr': float(cagr) if is_valid_number(cagr) else 0.0,
            'sharpe_ratio': float(sharpe) if is_valid_number(sharpe) else 0.0,
            'max_drawdown': float(max_dd) if is_valid_number(max_dd) else -10.0,
            'volatility': float(volatility) if is_valid_number(volatility) else 20.0,
            'cumulative_return': float(cumulative_return) if is_valid_number(cumulative_return) else 0.0,
            'ema_200': float(ema_200) if is_valid_number(ema_200) else float(stock_data['current_price']),
            'data_points': len(close_prices)
        }
        
        for key, value in result.items():
            if key not in ['ticker', 'name', 'data_points']:
                if not is_valid_number(value):
                    return None
        
        return result
    except Exception as e:
        return None


def calculate_composite_score(metrics_df):
    """Calculate composite score for ranking stocks with validation"""
    df = metrics_df.copy()
    
    df = df.dropna(subset=['cagr', 'sharpe_ratio', 'max_drawdown'])
    
    if len(df) == 0:
        return df
    
    cagr_range = df['cagr'].max() - df['cagr'].min()
    if cagr_range > 0:
        df['cagr_score'] = (df['cagr'] - df['cagr'].min()) / cagr_range * 100
    else:
        df['cagr_score'] = 50.0
    
    sharpe_range = df['sharpe_ratio'].max() - df['sharpe_ratio'].min()
    if sharpe_range > 0:
        df['sharpe_score'] = (df['sharpe_ratio'] - df['sharpe_ratio'].min()) / sharpe_range * 100
    else:
        df['sharpe_score'] = 50.0
    
    drawdown_range = df['max_drawdown'].max() - df['max_drawdown'].min()
    if drawdown_range > 0:
        df['drawdown_score'] = (df['max_drawdown'] - df['max_drawdown'].min()) / drawdown_range * 100
    else:
        df['drawdown_score'] = 50.0
    
    df['composite_score'] = (
        df['cagr_score'] * 0.40 +
        df['sharpe_score'] * 0.35 +
        df['drawdown_score'] * 0.25
    )
    
    df = df.dropna(subset=['composite_score'])
    
    return df


def allocate_capital_equal_weight(top_stocks, budget):
    """Allocate capital equally among selected stocks with validation"""
    top_stocks_clean = top_stocks[top_stocks['current_price'].notna() & (top_stocks['current_price'] > 0)].copy()
    
    if len(top_stocks_clean) == 0:
        return [], 0
    
    allocation_per_stock = budget / len(top_stocks_clean)
    
    allocations = []
    total_allocated = 0
    
    for _, stock in top_stocks_clean.iterrows():
        current_price = float(stock['current_price'])
        
        if not is_valid_number(current_price) or current_price <= 0:
            continue
        
        shares = max(1, int(allocation_per_stock / current_price))
        actual_allocation = shares * current_price
        
        allocations.append({
            'ticker': stock['ticker'],
            'allocation': float(actual_allocation),
            'shares': int(shares)
        })
        total_allocated += actual_allocation
    
    return allocations, total_allocated


def allocate_capital_risk_parity(top_stocks, budget):
    """Allocate capital inversely proportional to volatility with validation"""
    top_stocks_clean = top_stocks[
        (top_stocks['current_price'].notna()) & 
        (top_stocks['current_price'] > 0) &
        (top_stocks['volatility'].notna()) &
        (top_stocks['volatility'] > 0)
    ].copy()
    
    if len(top_stocks_clean) == 0:
        return allocate_capital_equal_weight(top_stocks, budget)
    
    top_stocks_clean['inv_volatility'] = 1 / (top_stocks_clean['volatility'] + 0.0001)
    total_inv_vol = top_stocks_clean['inv_volatility'].sum()
    
    if not is_valid_number(total_inv_vol) or total_inv_vol <= 0:
        return allocate_capital_equal_weight(top_stocks, budget)
    
    top_stocks_clean['weight'] = top_stocks_clean['inv_volatility'] / total_inv_vol
    
    allocations = []
    total_allocated = 0
    
    for _, stock in top_stocks_clean.iterrows():
        current_price = float(stock['current_price'])
        weight = float(stock['weight'])
        
        if not is_valid_number(current_price) or current_price <= 0:
            continue
        
        if not is_valid_number(weight) or weight <= 0:
            continue
        
        target_allocation = budget * weight
        shares = max(1, int(target_allocation / current_price))
        actual_allocation = shares * current_price
        
        allocations.append({
            'ticker': stock['ticker'],
            'allocation': float(actual_allocation),
            'shares': int(shares)
        })
        total_allocated += actual_allocation
    
    return allocations, total_allocated


def calculate_exit_signals(stock_data, allocation_data):
    """Calculate stop-loss, take-profit, and trailing stop signals with validation"""
    current_price = float(stock_data['current_price'])
    ema_200 = float(stock_data['ema_200'])
    shares = int(allocation_data['shares'])
    
    if not is_valid_number(current_price) or current_price <= 0:
        current_price = 100
    
    if not is_valid_number(ema_200) or ema_200 <= 0:
        ema_200 = current_price
    
    stop_loss = current_price * (1 - STOP_LOSS_PERCENT / 100)
    take_profit = current_price * (1 + TAKE_PROFIT_PERCENT / 100)
    
    trailing_stop_signal = "HOLD" if current_price > ema_200 else "EXIT"
    
    potential_profit = (take_profit - current_price) * shares
    potential_loss = (current_price - stop_loss) * shares
    
    risk_reward = potential_profit / potential_loss if potential_loss > 0 else 1.0
    
    return {
        'stop_loss_price': float(stop_loss),
        'take_profit_price': float(take_profit),
        'ema_200': float(ema_200),
        'trailing_stop_signal': trailing_stop_signal,
        'potential_profit': float(potential_profit),
        'potential_loss': float(potential_loss),
        'risk_reward_ratio': float(risk_reward)
    }


