def main():
    """Main execution function"""
    print("=" * 80)
    print("NIFTY 50 INVESTMENT ANALYZER - 5 YEAR HISTORICAL ANALYSIS (FINAL)")
    print("=" * 80)
    print(f"\n📊 Configuration:")
    print(f"   Budget: ₹{STARTING_BUDGET:,.2f}")
    print(f"   Lookback Period: {YEARS_LOOKBACK} years")
    print(f"   Stocks to Select: Top {TOP_N_STOCKS}")
    print(f"   Allocation Method: {ALLOCATION_METHOD.replace('_', ' ').title()}")
    print(f"   Stop-Loss: {STOP_LOSS_PERCENT}% | Take-Profit: {TAKE_PROFIT_PERCENT}%")
    print("\n" + "=" * 80)
    
    end_date = datetime.now()
    start_date = end_date - timedelta(days=YEARS_LOOKBACK * 365 + 30)
    
    print(f"\n📅 Fetching data from {start_date.strftime('%Y-%m-%d')} to {end_date.strftime('%Y-%m-%d')}")
    print(f"⏳ Analyzing {len(NIFTY_50_TICKERS)} Nifty 50 stocks... (This may take 2-3 minutes)\n")
    
    all_stock_data = []
    successful = 0
    failed = 0
    
    for idx, ticker in enumerate(NIFTY_50_TICKERS, 1):
        print(f"[{idx}/{len(NIFTY_50_TICKERS)}] Fetching {ticker}...", end=' ', flush=True)
        
        stock_data = fetch_stock_data(ticker, start_date, end_date)
        
        if stock_data:
            all_stock_data.append(stock_data)
            print(f"✓ ₹{stock_data['current_price']:.2f}")
            successful += 1
        else:
            print("✗")
            failed += 1
        
        if idx % 10 == 0:
            time.sleep(1)
    
    print(f"\n{'=' * 80}")
    print(f"Data Collection Complete: {successful} successful, {failed} failed")
    print(f"{'=' * 80}\n")
    
    if len(all_stock_data) < TOP_N_STOCKS:
        print(f"❌ Error: Not enough stocks fetched ({len(all_stock_data)}) to select top {TOP_N_STOCKS}")
        return
    
    print("🔍 Analyzing stock performance metrics...\n")
    all_metrics = []
    
    for stock_data in all_stock_data:
        metrics = analyze_stock(stock_data)
        if metrics:
            all_metrics.append(metrics)
    
    print(f"✓ Successfully analyzed {len(all_metrics)} stocks\n")
    
    if len(all_metrics) < TOP_N_STOCKS:
        print(f"❌ Error: Not enough valid stocks analyzed ({len(all_metrics)}) to select top {TOP_N_STOCKS}")
        return
    
    metrics_df = pd.DataFrame(all_metrics)
    
    metrics_df = calculate_composite_score(metrics_df)
    metrics_df = metrics_df.sort_values('composite_score', ascending=False).reset_index(drop=True)
    metrics_df['rank'] = range(1, len(metrics_df) + 1)
    
    top_stocks = metrics_df.head(TOP_N_STOCKS).copy()
    
    print("=" * 80)
    print(f"TOP {TOP_N_STOCKS} STOCKS SELECTED")
    print("=" * 80)
    for _, stock in top_stocks.iterrows():
        print(f"{int(stock['rank'])}. {stock['name']} ({stock['ticker']}) - Score: {stock['composite_score']:.2f}")
    print("=" * 80 + "\n")
    
    print(f"💰 Allocating ₹{STARTING_BUDGET:,.2f} using {ALLOCATION_METHOD.replace('_', ' ').title()} strategy...\n")
    
    if ALLOCATION_METHOD == 'equal_weight':
        allocations, total_allocated = allocate_capital_equal_weight(top_stocks, STARTING_BUDGET)
    else:
        allocations, total_allocated = allocate_capital_risk_parity(top_stocks, STARTING_BUDGET)
    
    if len(allocations) == 0:
        print("❌ Error: Failed to allocate capital")
        return
    
    allocation_dict = {alloc['ticker']: alloc for alloc in allocations}
    
    portfolio_data = []
    
    for _, stock in top_stocks.iterrows():
        ticker = stock['ticker']
        
        if ticker not in allocation_dict:
            continue
        
        allocation_data = allocation_dict[ticker]
        
        original_data = next((s for s in all_metrics if s['ticker'] == ticker), None)
        
        if original_data:
            exit_signals = calculate_exit_signals(original_data, allocation_data)
            
            portfolio_data.append({
                'Rank': int(stock['rank']),
                'Ticker': ticker.replace('.NS', ''),
                'Company Name': stock['name'],
                'Current Price': float(stock['current_price']),
                'Shares to Buy': int(allocation_data['shares']),
                'Investment Amount': float(allocation_data['allocation']),
                'Allocation %': float((allocation_data['allocation'] / total_allocated) * 100),
                'Stop-Loss Price': float(exit_signals['stop_loss_price']),
                'Take-Profit Price': float(exit_signals['take_profit_price']),
                'Potential Profit': float(exit_signals['potential_profit']),
                'Potential Loss': float(exit_signals['potential_loss']),
                'Risk/Reward': float(exit_signals['risk_reward_ratio']),
                'Exit Signal (EMA200)': exit_signals['trailing_stop_signal']
            })
    
    portfolio_df = pd.DataFrame(portfolio_data)
    
    all_stocks_df = metrics_df[[
        'rank', 'ticker', 'name', 'current_price', 'cagr', 'sharpe_ratio',
        'max_drawdown', 'volatility', 'cumulative_return', 'composite_score'
    ]].copy()
    
    all_stocks_df.columns = [
        'Rank', 'Ticker', 'Company Name', 'Current Price', 'CAGR (%)',
        'Sharpe Ratio', 'Max Drawdown (%)', 'Volatility (%)', 
        'Cumulative Return (%)', 'Composite Score'
    ]
    
    all_stocks_df['Ticker'] = all_stocks_df['Ticker'].str.replace('.NS', '')
    
    print("=" * 80)
    print("PORTFOLIO SUMMARY")
    print("=" * 80)
    print(f"Total Budget: ₹{STARTING_BUDGET:,.2f}")
    print(f"Amount Invested: ₹{total_allocated:,.2f}")
    print(f"Remaining: ₹{STARTING_BUDGET - total_allocated:,.2f}")
    print(f"Number of Stocks: {len(portfolio_df)}")
    print(f"\nTotal Potential Profit: ₹{portfolio_df['Potential Profit'].sum():,.2f}")
    print(f"Total Potential Loss: ₹{portfolio_df['Potential Loss'].sum():,.2f}")
    
    if portfolio_df['Potential Loss'].sum() > 0:
        print(f"Portfolio Risk/Reward: {portfolio_df['Potential Profit'].sum() / portfolio_df['Potential Loss'].sum():.2f}")
    
    print("=" * 80 + "\n")
    
    print("TOP 5 INVESTMENTS:")
    print("-" * 80)
    for _, row in portfolio_df.head(5).iterrows():
        print(f"{row['Rank']}. {row['Company Name']} ({row['Ticker']})")
        print(f"   Investment: ₹{row['Investment Amount']:,.2f} ({row['Allocation %']:.1f}%) - {row['Shares to Buy']} shares @ ₹{row['Current Price']:.2f}")
        print(f"   Stop-Loss: ₹{row['Stop-Loss Price']:.2f} | Take-Profit: ₹{row['Take-Profit Price']:.2f}")
        print(f"   Risk/Reward: {row['Risk/Reward']:.2f} | EMA200 Signal: {row['Exit Signal (EMA200)']}")
        print()
    
    print("\n📊 Generating Excel report...")
    create_excel_report(portfolio_df, all_stocks_df)
    
    print("\n" + "=" * 80)
    print("✅ ANALYSIS COMPLETE!")
